import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:go_router/go_router.dart';

final authProvider = StateNotifierProvider<AuthNotifier, AuthState>(
  (ref) => AuthNotifier(),
);

final routerProvider = Provider<GoRouter>((ref) {
  // refreshListenable triggers re-evaluation of redirects on auth change
  final refresh = GoRouterRefreshListenable(ref.watch(authProvider.notifier).stream);

  return GoRouter(
    initialLocation: '/',
    refreshListenable: refresh,
    redirect: (context, state) {
      final auth = ref.read(authProvider);
      final loggingIn = state.matchedLocation == '/login';
      final loading   = state.matchedLocation == '/splash';

      // Still hydrating auth — don't redirect anywhere
      if (auth is AuthLoading) return loading ? null : '/splash';

      // Anonymous user trying to access an app screen → /login
      if (auth is Anonymous && !loggingIn) {
        // Remember intended destination so we can come back
        return '/login?from=${Uri.encodeComponent(state.matchedLocation)}';
      }

      // Signed-in user lingering on /login or /splash → /home
      if (auth is Authenticated && (loggingIn || loading)) {
        final from = state.uri.queryParameters['from'];
        return from ?? '/home';
      }

      return null;                            // proceed as requested
    },
    routes: [
      GoRoute(path: '/splash', builder: (_, __) => const SplashPage()),
      GoRoute(path: '/login',  builder: (_, __) => const LoginPage()),
      ShellRoute(
        builder: (_, __, child) => BottomNavShell(child: child),
        routes: [
          GoRoute(path: '/home',    builder: (_, __) => const HomePage()),
          GoRoute(path: '/cart',    builder: (_, __) => const CartPage()),
          GoRoute(path: '/settings',builder: (_, __) => const SettingsPage()),
        ],
      ),
      GoRoute(
        path: '/admin',
        // ✅ Per-route redirect — admin only
        redirect: (context, state) {
          final user = switch (ref.read(authProvider)) { Authenticated(:final user) => user, _ => null };
          return user?.isAdmin == true ? null : '/home';
        },
        builder: (_, __) => const AdminConsole(),
      ),
    ],
  );
});

// Helper to bridge a stream into a Listenable for go_router
class GoRouterRefreshListenable extends ChangeNotifier {
  GoRouterRefreshListenable(Stream<dynamic> stream) {
    notifyListeners();                        // initial poke
    _sub = stream.listen((_) => notifyListeners());
  }
  late final StreamSubscription _sub;
  @override void dispose() { _sub.cancel(); super.dispose(); }
}

