import 'package:app_links/app_links.dart';

final _appLinks = AppLinks();

Future<void> bootstrapLinks(GoRouter router) async {
  // Cold start — was the app launched from a URL?
  final initial = await _appLinks.getInitialAppLink();
  if (initial != null) router.go(initial.path + (initial.query.isNotEmpty ? '?${initial.query}' : ''));

  // While running
  _appLinks.uriLinkStream.listen((uri) => router.go(uri.path));
}

