// ── go_router — CustomTransitionPage ──
import 'package:go_router/go_router.dart';

GoRoute(
  path: '/photo/:id',
  pageBuilder: (context, state) => CustomTransitionPage<void>(
    key: state.pageKey,
    child: PhotoPage(id: state.pathParameters['id']!),
    transitionDuration: const Duration(milliseconds: 250),
    transitionsBuilder: (context, anim, secondary, child) {
      // Slide up + fade in
      final slide = Tween(begin: const Offset(0, 0.12), end: Offset.zero)
          .animate(CurvedAnimation(parent: anim, curve: Curves.easeOut));
      return FadeTransition(
        opacity: anim,
        child: SlideTransition(position: slide, child: child),
      );
    },
  ),
);

// ── Coordinated transitions using secondaryAnimation ──
// Previous screen scales down as the new one comes in
transitionsBuilder: (context, anim, secondary, child) {
  final outgoing = Tween(begin: 1.0, end: 0.92).animate(secondary);
  // The CHILD here is the destination route; the outgoing scale applies to the
  // route below it, which runs the SAME transitionsBuilder against secondary.
  return ScaleTransition(scale: outgoing, child: SlideTransition(
    position: Tween(begin: const Offset(1, 0), end: Offset.zero).animate(anim),
    child: child,
  ));
};

